import { CACHE_MEMORY_LIMIT } from '../constants';

export class NordicAssetCacheLimitError extends Error {
  constructor(assetName: string) {
    super(
      `An error occurred while saving into file system cache: Asset "${assetName}" exceeds the memory limit of ` +
        `${CACHE_MEMORY_LIMIT / 1000000}MB defined for the cache.`,
    );
    this.name = 'NordicAssetCacheLimitError';
  }
}
